def validate_iban(iban: str) -> bool:
    if not isinstance(iban, str):
        return False

    iban = iban.replace(" ", "").upper()

    country_lengths = {
        "AL": 28, "AD": 24, "AT": 20, "AZ": 28, "BH": 22, "BE": 16, "BA": 20, "BR": 29, "BG": 22, "CR": 21,
        "HR": 21, "CY": 28, "CZ": 24, "DK": 18, "DO": 28, "EE": 20, "FO": 18, "FI": 18, "FR": 27, "GE": 22,
        "DE": 22, "GI": 23, "GR": 27, "GL": 18, "GT": 28, "HU": 28, "IS": 26, "IE": 22, "IL": 23, "IT": 27,
        "JO": 30, "KZ": 20, "XK": 20, "KW": 30, "LV": 21, "LB": 28, "LI": 21, "LT": 20, "LU": 20, "MT": 31,
        "MR": 27, "MU": 30, "MD": 24, "MC": 27, "ME": 22, "NL": 18, "MK": 19, "NO": 15, "PK": 24, "PS": 29,
        "PL": 28, "PT": 25, "QA": 29, "RO": 24, "SM": 27, "ST": 25, "SA": 24, "RS": 22, "SK": 24, "SI": 19,
        "ES": 24, "SE": 24, "CH": 21, "TN": 24, "TR": 26, "AE": 23, "GB": 22, "VA": 22, "VG": 24
    }

    if len(iban) < 4:
        return False

    country_code = iban[0:2]
    if country_code not in country_lengths:
        return False

    expected_length = country_lengths[country_code]
    if len(iban) != expected_length:
        return False

    if not iban.isalnum():
        return False

    if not (iban[0:2].isalpha() and iban[2:4].isdigit()):
        return False

    rearranged_iban = iban[4:] + iban[0:4]

    numeric_string_parts = []
    for char in rearranged_iban:
        if 'A' <= char <= 'Z':
            numeric_string_parts.append(str(ord(char) - ord('A') + 10))
        else:
            numeric_string_parts.append(char)

    numeric_iban = "".join(numeric_string_parts)

    try:
        return int(numeric_iban) % 97 == 1
    except ValueError:
        return False
